// 【VIP规则：达标毕业清理（防无效流量）】
(maindata, torrent) => {
  const categoryList = ["不删", "keep"]; 
  const { ratio, category, progress } = torrent.originProp;

  if (categoryList.indexOf(category) !== -1) return false;

  // 必须下载完成，且分享率跑到 3 立刻杀掉，停止无效的“盒子义务劳动”
  if (progress >= 1 && ratio >= 3) {
    return true; 
  }

  return false;
};
